import {describe, expect, it} from "vitest";
import {expandRect, pointInRect, rectContains, rectsEqual, unionRect} from "../../bounding-rect";

describe("pointInRect", () => {
    const rect = {x: 10, y: 20, w: 5, h: 4};

    it("includes points on the edges", () => {
        expect(pointInRect(10, 20, rect)).toBe(true);
        expect(pointInRect(15, 24, rect)).toBe(true);
    });

    it("excludes points outside", () => {
        expect(pointInRect(9, 20, rect)).toBe(false);
        expect(pointInRect(16, 24, rect)).toBe(false);
        expect(pointInRect(10, 25, rect)).toBe(false);
    });
});

describe("rectsEqual", () => {
    it("compares all fields", () => {
        expect(rectsEqual({x: 1, y: 2, w: 3, h: 4}, {x: 1, y: 2, w: 3, h: 4})).toBe(true);
        expect(rectsEqual({x: 1, y: 2, w: 3, h: 4}, {x: 1, y: 2, w: 3, h: 5})).toBe(false);
    });
});

describe("rectContains", () => {
    it("returns true for fully-contained rectangles", () => {
        const outer = {x: 0, y: 0, w: 10, h: 10};
        const inner = {x: 2, y: 3, w: 4, h: 2};
        expect(rectContains(outer, inner)).toBe(true);
    });

    it("returns false when inner overflows any side", () => {
        const outer = {x: 0, y: 0, w: 10, h: 10};
        expect(rectContains(outer, {x: -1, y: 0, w: 2, h: 2})).toBe(false);
        expect(rectContains(outer, {x: 9, y: 9, w: 2, h: 2})).toBe(false);
    });
});

describe("unionRect", () => {
    it("creates the smallest rect that covers both inputs", () => {
        const a = {x: 1, y: 1, w: 4, h: 3};
        const b = {x: 3, y: -1, w: 5, h: 4};
        expect(unionRect(a, b)).toEqual({x: 1, y: -1, w: 7, h: 5});
    });
});

describe("expandRect", () => {
    it("grows rectangle by positive spacing", () => {
        const rect = {x: 5, y: 10, w: 20, h: 8};
        expect(expandRect(rect, [1, 2, 3, 4])).toEqual({x: 1, y: 9, w: 26, h: 12});
    });

    it("shrinks rectangle with negative spacing", () => {
        const rect = {x: 5, y: 10, w: 20, h: 8};
        expect(expandRect(rect, [-1, -2, -3, -4])).toEqual({x: 9, y: 11, w: 14, h: 4});
    });
});

import {describe, expect, it, vi} from "vitest";
import {button, checkbox, hr, line, numberBox, radio, select, textbox} from "../../builders/input";
import {style} from "../../builders/style";

describe("input builders", () => {
    it("normalises StyleBuilder fields in button props", () => {
        const onClick = vi.fn();
        const built = button({
            content: "Run",
            focusedStyle: style().foreground("#fff").background("#00f"),
            onClick,
        });

        expect(built.kind).toBe("button");
        expect(built.focusedStyle).toEqual({foreground: "#fff", background: "#00f"});
    });

    it("builds checkbox kind literal and preserves props", () => {
        const onToggle = vi.fn();
        const built = checkbox({checked: true, onToggle});
        expect(built).toMatchObject({kind: "checkbox", checked: true, onToggle});
    });

    it("builds radio/select/textbox/number kinds correctly", () => {
        const onSelect = vi.fn();
        const onTextChange = vi.fn(() => true);
        const onNumberChange = vi.fn();

        const builtRadio = radio({options: [{key: "a"}], selected: "a", onSelect});
        const builtSelect = select({options: [{key: "a"}], selected: "a", onSelect});
        const builtTextbox = textbox({value: "abc", onChange: onTextChange});
        const builtNumber = numberBox({value: 5, onChange: onNumberChange});

        expect(builtRadio.kind).toBe("radio");
        expect(builtSelect.kind).toBe("select");
        expect(builtTextbox.kind).toBe("textbox");
        expect(builtNumber.kind).toBe("number");
    });

    it("builds hr with defaults when props omitted", () => {
        expect(hr()).toEqual({kind: "hr"});
    });
});

describe("LineBuilder", () => {
    it("appends string and display items in order", () => {
        const row = line()
            .content("Label")
            .content(button({content: "Ok", onClick: () => undefined}));

        expect(row.items[0]).toEqual({content: "Label"});
        expect(row.items[1]).toMatchObject({kind: "button", content: "Ok"});
    });

    it("returns this for fluent chaining", () => {
        const row = line();
        expect(row.content("A")).toBe(row);
    });
});

import {describe, expect, it} from "vitest";
import {resolveSpacing, spacing, ZERO_SPACING} from "../../spacing";

describe("resolveSpacing", () => {
    it("returns ZERO_SPACING for undefined", () => {
        expect(resolveSpacing(undefined)).toBe(ZERO_SPACING);
    });

    it("expands a single number to all sides", () => {
        expect(resolveSpacing(3)).toEqual([3, 3, 3, 3]);
    });

    it("expands [vertical, horizontal] into [top, right, bottom, left]", () => {
        expect(resolveSpacing([2, 5])).toEqual([2, 5, 2, 5]);
    });

    it("passes through full 4-tuple spacing unchanged", () => {
        expect(resolveSpacing([1, 2, 3, 4])).toEqual([1, 2, 3, 4]);
    });
});

describe("spacing helper", () => {
    it("builds one-value shorthand", () => {
        expect(spacing(4)).toEqual([4]);
    });

    it("builds two-value shorthand", () => {
        expect(spacing(4, 6)).toEqual([4, 6]);
    });

    it("builds four-value shorthand", () => {
        expect(spacing(1, 2, 3, 4)).toEqual([1, 2, 3, 4]);
    });
});

import {describe, expect, it} from "vitest";
import {resolveStateStyle} from "../../state-style";

describe("resolveStateStyle", () => {
    it("falls back to base values when style is undefined", () => {
        const base = {foreground: "#111", background: "#222"};
        expect(resolveStateStyle(undefined, base)).toEqual(base);
    });

    it("overrides base fields when style defines them", () => {
        const base = {foreground: "#111", background: "#222"};
        const resolved = resolveStateStyle({foreground: "#aaa"}, base);
        expect(resolved).toEqual({foreground: "#aaa", background: "#222"});
    });

    it("inverts resolved colours when invert is true and background resolves", () => {
        const base = {foreground: "#111", background: "#222"};
        const resolved = resolveStateStyle({foreground: "#aaa", invert: true}, base);
        expect(resolved).toEqual({foreground: "#222", background: "#aaa"});
    });

    it("does not invert when resolved background is undefined", () => {
        const base = {foreground: "#111", background: undefined};
        const resolved = resolveStateStyle({invert: true}, base);
        expect(resolved).toEqual({foreground: "#111", background: undefined});
    });
});

import {describe, expect, it} from "vitest";
import {content, style} from "../../builders/style";
import {TextFormat} from "../../text-style";

describe("StyleBuilder", () => {
    it("builds chained style fields", () => {
        const built = style()
            .foreground("#fff")
            .background("#000")
            .fontFamily("monospace")
            .fontSize(14)
            .invert()
            .fontSizeDelta(-2)
            .build();

        expect(built).toEqual({
            foreground: "#fff",
            background: "#000",
            fontFamily: "monospace",
            fontSize: 14,
            invert: true,
            fontSizeDelta: -2,
        });
    });

    it("sets and clears format flags independently", () => {
        const built = style()
            .bold()
            .italic()
            .underline()
            .italic(false)
            .build();

        expect(built.format).toBe(TextFormat.BOLD | TextFormat.UNDERLINE);
    });

    it("sets and clears invert-format flags independently", () => {
        const built = style()
            .unbold()
            .unitalic()
            .ununderline(false)
            .build();

        expect(built.invertFormat).toBe(TextFormat.BOLD | TextFormat.ITALIC);
    });

    it("wraps text with content helper", () => {
        expect(content("hello")).toEqual({content: "hello"});
    });
});

import {PopupController} from "@lib/popup/popup-controller";
import {KeyBinding} from "../help/key-binding";

/**
 * App-level popup controller base for popups that expose their own key bindings.
 */
export abstract class KeyBindingPopupController extends PopupController {
    /**
     * This controller's own key bindings, for the help popup to list.
     *
     * @returns This controller's key bindings.
     */
    public abstract getKeyBindings(): KeyBinding[];
}

import {World} from "./world/world";
import {ChunkWorkerClient} from "./world/generation/chunk-worker-client";
import {Camera} from "./camera/camera";
import {CameraDragController} from "./camera/camera-drag-controller";
import {MovementController} from "./entities/movement-controller";
import {Vector2d} from "./geometry/vector2d";
import {DebugController} from "./debug/debug-controller";
import {FrameLoopController} from "@lib/frames/FrameLoopController";
import {requireNonNull} from "./util";
import {HelpController} from "./help/help-controller";
import {KeyBinding} from "./help/key-binding";
import {SettingsController} from "./settings/settings-controller";
import {PopupController} from "@lib/popup/popup-controller";

/**
 * Owns everything needed to run the game against a canvas.
 */
export class WorldController {
    /** Width/height of a single tile, in canvas pixels. */
    private static readonly TILE_SIZE = 8;

    /** Value the settings popup's target-FPS field shows when uncapped (i.e. {@link getTargetFps} returns `undefined`). */
    private static readonly DEFAULT_TARGET_FPS = 60;

    /** FPS the render loop is throttled to while a popup is open, since popups don't need to be responsive. */
    private static readonly POPUP_TARGET_FPS = 20;

    private readonly canvas: HTMLCanvasElement;
    private readonly ctx: CanvasRenderingContext2D;
    private readonly world: World;
    private readonly camera: Camera;
    private readonly movementController: MovementController;
    private readonly debugController: DebugController;
    private readonly helpController: HelpController;
    private readonly settingsController: SettingsController;
    private readonly popupControllers: PopupController[];
    private readonly frameLoop: FrameLoopController;

    private lastTickTime = 0;

    /** Whichever popup source is currently open, or `null` if none is. While set, the world is paused and the render loop is throttled. */
    private activePopupController: PopupController | null = null;

    /**
     * A copy of the canvas taken the moment a popup opened.
     */
    private worldSnapshot: OffscreenCanvas | null = null;

    /** The user's configured FPS cap, kept separate from whatever {@link frameLoop} is currently doing so the popup throttle doesn't clobber it. */
    private userTargetFps: number | undefined;

    /** Name of the `NoiseField` currently rendered as a debug heatmap, or `undefined` for none. */
    private noiseFieldName: string | undefined;

    /**
     * @param canvas - Canvas to render the world into.
     * @param targetFps - FPS to cap rendering at. Defaults to `undefined` (uncapped).
     */
    public constructor(canvas: HTMLCanvasElement, targetFps?: number) {
        this.canvas = canvas;
        this.ctx = requireNonNull(canvas.getContext("2d"));

        this.world = new World(WorldController.TILE_SIZE);
        this.camera = new Camera(Vector2d.ZERO, window.innerWidth, window.innerHeight);
        new CameraDragController(canvas, this.camera);
        this.movementController = new MovementController(this.world.getMainEntity(), {camera: this.camera, mode: "edge"});
        this.debugController = new DebugController(
            () => this.world.reloadAllChunks(),
            () => this.world.teleportMainEntityTo(this.camera.getCenter()),
            () => this.movementController.isSpectating(),
        );
        this.helpController = new HelpController(() => this.getKeyBindings(), this.handlePopupOpenChange);
        this.settingsController = new SettingsController(
            () => this.movementController.getCameraFollowMode(),
            (mode) => this.movementController.setCameraFollowMode(mode),
            () => this.movementController.isSpectating(),
            (spectating) => this.movementController.setSpectating(spectating),
            () => this.debugController.isEnabled(),
            (enabled) => this.debugController.setEnabled(enabled),
            () => this.world.isGenerationEnabled(),
            (enabled) => this.world.setGenerationEnabled(enabled),
            () => this.getTargetFps() ?? WorldController.DEFAULT_TARGET_FPS,
            (fps) => this.setTargetFps(fps),
            () => this.world.getNoiseFieldNames(),
            () => this.noiseFieldName,
            (name) => this.noiseFieldName = name,
            () => this.world.getWorldSeed(),
            (seed) => this.world.setWorldSeed(seed),
            () => this.world.refreshWorldSeed(),
            this.handlePopupOpenChange,
        );
        this.popupControllers = [this.helpController, this.settingsController];
        this.userTargetFps = targetFps;
        this.frameLoop = new FrameLoopController(this.onFrame, targetFps);

        window.addEventListener("resize", this.resize);
        this.resize();
    }

    /**
     * Starts the render loop.
     */
    public start(): void {
        this.lastTickTime = performance.now();
        this.frameLoop.start();
    }

    /**
     * Stops the render loop.
     */
    public stop(): void {
        this.frameLoop.stop();
    }

    /**
     * Returns the user's configured FPS cap, or `undefined` when uncapped.
     * Unaffected by the throttle applied while a popup is open.
     */
    public getTargetFps(): number | undefined {
        return this.userTargetFps;
    }

    /**
     * Sets the user's FPS cap. Pass `undefined` to render on every available
     * `requestAnimationFrame` callback. If a popup is currently open, the
     * loop stays throttled and this cap takes effect once it closes.
     */
    public setTargetFps(fps: number | undefined): void {
        this.userTargetFps = fps;
        if (!this.activePopupController) {
            this.frameLoop.setTargetFps(fps);
        }
    }

    /**
     * Returns the currently measured rendering FPS.
     */
    public getActualFps(): number {
        return this.frameLoop.getActualFps();
    }

    /**
     * The worker client driving chunk generation - for debugging (see
     * `exposeGlobals`).
     */
    public getChunkWorkerClient(): ChunkWorkerClient {
        return this.world.getChunkWorkerClient();
    }

    /**
     * The running game's `World`.
     */
    public getWorld(): World {
        return this.world;
    }

    private readonly resize = (): void => {
        this.canvas.width = window.innerWidth;
        this.canvas.height = window.innerHeight;
        this.camera.setViewportSize(this.canvas.width, this.canvas.height);

        if (this.activePopupController) {
            this.repaintWorldSnapshot();
            this.activePopupController.drawOverlay(this.ctx, this.canvas.width, this.canvas.height);
            this.activePopupController.draw(this.ctx, this.canvas.width, this.canvas.height);
            return;
        }

        this.draw();
    };

    /**
     * Runs whenever any popup opens or closes.
     */
    private readonly handlePopupOpenChange = (): void => {
        this.activePopupController = this.popupControllers.find((source) => source.isOpen()) ?? null;
        this.frameLoop.setTargetFps(this.activePopupController ? WorldController.POPUP_TARGET_FPS : this.userTargetFps);

        if (this.activePopupController) {
            this.worldSnapshot = this.captureWorldSnapshot();
            this.activePopupController.drawOverlay(this.ctx, this.canvas.width, this.canvas.height);
            this.activePopupController.draw(this.ctx, this.canvas.width, this.canvas.height);
        } else {
            this.worldSnapshot = null;
        }
    };

    /**
     * Copies the canvas's current pixels into an {@link OffscreenCanvas}.
     */
    private captureWorldSnapshot(): OffscreenCanvas {
        const snapshot = new OffscreenCanvas(this.canvas.width, this.canvas.height);
        requireNonNull(snapshot.getContext("2d")).drawImage(this.canvas, 0, 0);
        return snapshot;
    }

    /** Re-blits the frozen {@link worldSnapshot} over the whole canvas - passed to a popup as its `repaintBackground` hook. */
    private readonly repaintWorldSnapshot = (): void => {
        this.ctx.drawImage(requireNonNull(this.worldSnapshot), 0, 0, this.canvas.width, this.canvas.height);
    };

    private readonly onFrame = (now: DOMHighResTimeStamp): void => {
        const deltaMs = now - this.lastTickTime;
        this.lastTickTime = now;

        if (this.activePopupController) {
            this.activePopupController.draw(this.ctx, this.canvas.width, this.canvas.height, this.repaintWorldSnapshot);
            return;
        }

        this.world.update(deltaMs, this.camera, this.movementController.isSpectating());
        this.movementController.update(deltaMs);
        this.draw();
    };

    /**
     * Repaints the world. Only ever called while no popup is open - see
     * {@link onFrame}/{@link resize}, which paint the popup (and, for
     * {@link resize}, the frozen world snapshot) instead while one is.
     */
    private draw(): void {
        this.world.draw(
            this.ctx,
            this.camera,
            this.debugController.isEnabled(),
            this.movementController.isSpectating(),
            this.frameLoop.getActualFps(),
            this.frameLoop.getTargetFps(),
            this.noiseFieldName,
        );
    }

    /**
     * Every key binding in the game, gathered from every controller (and the
     * main entity) that exposes one.
     */
    private getKeyBindings(): KeyBinding[] {
        const all = [
            ...this.movementController.getKeyBindings(),
            ...this.debugController.getKeyBindings(),
            ...this.popupControllers.flatMap((source) => source.getKeyBindings()),
            ...(this.world.getMainEntity().getKeyBindings?.() ?? []),
        ];
        const seenKeys = new Set<string>();
        return all.filter((binding) => {
            if (seenKeys.has(binding.key)) {
                return false;
            }
            seenKeys.add(binding.key);
            return true;
        });
    }
}

